(function () {
  const runtimeOrigin = window.location.origin && window.location.origin !== 'null'
    ? window.location.origin
    : '';
  const baseUrl = runtimeOrigin.replace(/\/$/, '');
  const logoUrl = baseUrl + '/poison-well-records-logo-ventura-805-punk-label.png';
  const bandcampUrl = 'https://poisonwellrecords.bandcamp.com';
  const discordRequestUrl = 'mailto:poisonwellrecords@gmail.com?subject=Discord%20Invite%20Request';
  const pathMap = {
    'index.html': '/',
    'ventura-punk-vinyl.html': '/ventura-punk-vinyl',
    'apparel.html': '/apparel',
    'ventura-punk-record-store-online.html': '/ventura-punk-record-store-online',
    '805-punk-bands.html': '/805-punk-bands',
    'about-poison-well-records.html': '/about-poison-well-records',
    'contact-wholesale.html': '/contact-wholesale',
    'faq.html': '/faq',
    'dr-know-live-cbgb-1989-ventura-hardcore.html': '/dr-know-live-cbgb-1989-ventura-hardcore',
    'music-videos.html': '/music-videos',
    'press.html': '/press',
    '805-punk-shows-events.html': '/805-punk-shows-events',
    'success.html': '/success',
    'order-confirmation.html': '/order-confirmation',
    'checkout-cancelled.html': '/checkout-cancelled'
  };

  function currentFile() {
    const p = window.location.pathname;
    const f = p.split('/').pop();
    return f || 'index.html';
  }

  function currentCanonical() {
    const file = currentFile();
    const path = pathMap[file] || '/';
    return baseUrl ? (baseUrl + path) : path;
  }

  function normalizePath(pathname) {
    let path = pathname || '/';
    if (!path.startsWith('/')) path = '/' + path;
    if (path.length > 1 && path.endsWith('/')) path = path.slice(0, -1);
    if (path.endsWith('.html')) path = path.slice(0, -5);
    return path || '/';
  }

  function markCurrentNavLink() {
    const currentPath = normalizePath(window.location.pathname);
    const navLinks = document.querySelectorAll('header nav a[href]');
    navLinks.forEach(function (link) {
      const href = link.getAttribute('href') || '';
      if (!href || href.startsWith('#') || href.indexOf('mailto:') === 0 || href.indexOf('http') === 0) return;
      const hrefPath = normalizePath(href.split('#')[0]);
      if (hrefPath === currentPath) {
        link.setAttribute('aria-current', 'page');
      } else {
        link.removeAttribute('aria-current');
      }
    });
  }

  function ensureGeoMeta() {
    const metas = [
      { name: 'geo.region', content: 'US-CA' },
      { name: 'geo.placename', content: 'Ventura' },
      { name: 'geo.position', content: '34.2746;-119.2290' },
      { name: 'ICBM', content: '34.2746, -119.2290' }
    ];
    metas.forEach(m => {
      if (!document.querySelector(`meta[name="${m.name}"]`)) {
        const el = document.createElement('meta');
        el.name = m.name;
        el.content = m.content;
        document.head.appendChild(el);
      }
    });
  }

  function ensureFavicon() {
    if (!document.querySelector('link[rel*="icon"]')) {
      const link = document.createElement('link');
      link.rel = 'icon';
      link.type = 'image/png';
      link.href = logoUrl;
      document.head.appendChild(link);
    }
  }

  function ensureAlertBar() {
    const header = document.querySelector('.site-header, .topbar, header');
    if (!header) return;
    const releaseAnnouncement = document.body.getAttribute('data-release-announcement') || 'Dr. Know - Live CBGB 1989';
    const alertMarkup =
      '<div class="alert-marquee">' +
      '<span>NEW RELEASE ANNOUNCEMENT: <strong>' + releaseAnnouncement + '</strong> is live now. <a href="dr-know-live-cbgb-1989-ventura-hardcore.html">VIEW &amp; BUY -></a></span>' +
      '</div>';
    const existing = document.querySelector('.alert-bar');
    if (existing) {
      existing.innerHTML = alertMarkup;
      return;
    }
    const alertBar = document.createElement('div');
    alertBar.className = 'alert-bar';
    alertBar.setAttribute('role', 'region');
    alertBar.setAttribute('aria-label', 'Limited pressing alert');
    alertBar.innerHTML = alertMarkup;
    header.insertAdjacentElement('afterend', alertBar);
  }

  function ensureVinylBackground() {
    let spinner = document.querySelector('.vinyl-bg-spinner');
    if (!spinner) {
      spinner = document.createElement('div');
      spinner.className = 'vinyl-bg-spinner';
      spinner.setAttribute('aria-hidden', 'true');
      document.body.insertAdjacentElement('afterbegin', spinner);
    }
    let labelEl = document.querySelector('.vinyl-band-label');
    if (!labelEl) {
      labelEl = document.createElement('span');
      labelEl.className = 'vinyl-band-label';
      labelEl.setAttribute('aria-hidden', 'true');
      document.body.appendChild(labelEl);
    }
    const bandLabels = {
      'index.html': { band: 'Dr. Know', color: '#e85c0d', label: 'CBGB 1989' },
      'ventura-punk-record-store-online.html': { band: 'RAW', color: '#f5a623', label: 'Sick Love' },
      'apparel.html': { band: 'Poison Well', color: '#cc2200', label: '805 Merch' },
      '805-punk-bands.html': { band: 'I Decline', color: '#b5651d', label: 'SoCal HC' },
      'about-poison-well-records.html': { band: 'Narthex', color: '#8b4513', label: '1984' },
      'contact-wholesale.html': { band: 'Front Street', color: '#d2691e', label: 'Knuckle Draggers' },
      'faq.html': { band: 'Los Bonedrivers', color: '#cd853f', label: 'Distro' },
      'dr-know-live-cbgb-1989-ventura-hardcore.html': { band: 'Dr. Know', color: '#ff4500', label: 'Live CBGB' }
    };
    const currentPath = normalizePath(window.location.pathname);
    const data = bandLabels[currentPath] || bandLabels['/'];
    spinner.style.setProperty('--label-color', data.color);
    spinner.setAttribute('data-band', data.band);
    labelEl.textContent = data.band.toUpperCase();
    labelEl.style.color = data.color;
  }

  function initNavToggle() {
    const toggle = document.getElementById('nav-toggle');
    const nav = document.getElementById('nav-links');
    if (!toggle || !nav) return;
    toggle.addEventListener('click', function () {
      const isOpen = toggle.getAttribute('aria-expanded') === 'true';
      toggle.setAttribute('aria-expanded', !isOpen);
      nav.classList.toggle('open');
      document.body.classList.toggle('nav-open');
    });
  }

  function initBackToTop() {
    if (document.querySelector('.back-to-top')) return;
    const btn = document.createElement('button');
    btn.className = 'back-to-top';
    btn.setAttribute('aria-label', 'Back to top');
    btn.innerHTML = '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="m18 15-6-6-6 6"/></svg>';
    document.body.appendChild(btn);
    window.addEventListener('scroll', function () {
      if (window.scrollY > 400) btn.classList.add('visible');
      else btn.classList.remove('visible');
    });
    btn.addEventListener('click', function () { window.scrollTo({ top: 0, behavior: 'smooth' }); });
  }

  function ensureFooterCredit() {
    document.querySelectorAll('.footer-credit').forEach(function (node) {
      node.remove();
    });
  }

  function setMetaProperty(property, content) {
    if (!content) return;
    let node = document.querySelector('meta[property="' + property + '"]');
    if (!node) {
      node = document.createElement('meta');
      node.setAttribute('property', property);
      document.head.appendChild(node);
    }
    node.setAttribute('content', content);
  }

  function sanitizeBrandArtifacts() {
    document.querySelectorAll('a[href="https://poisonwellrecords.bandcamp.com/dashboard"]').forEach(function (link) {
      link.href = bandcampUrl;
      if ((link.textContent || '').trim() === 'poisonwellrecords.bandcamp.com') {
        link.textContent = 'poisonwellrecords.bandcamp.com';
      }
    });

    document.querySelectorAll('a[href="https://discord.gg/invitelink"]').forEach(function (link) {
      link.href = discordRequestUrl;
      link.title = 'Request Discord Invite';
      link.removeAttribute('target');
      link.setAttribute('rel', 'noopener');
    });

    const canonicalLinks = Array.from(document.querySelectorAll('link[rel="canonical"]'));
    canonicalLinks.slice(1).forEach(function (link) { link.remove(); });

    const identityScripts = Array.from(document.querySelectorAll('script[src="https://identity.netlify.com/v1/netlify-identity-widget.js"]'));
    identityScripts.slice(1).forEach(function (script) { script.remove(); });

    document.querySelectorAll('script[type="application/ld+json"]').forEach(function (node) {
      const text = node.textContent || '';
      if (
        text.indexOf('poisonwellrecords.netlify.app') !== -1 ||
        text.indexOf('poisonwellrecords.com') !== -1 ||
        text.indexOf('bandcamp.com/dashboard') !== -1 ||
        text.indexOf('XXX-XXX-XXXX') !== -1
      ) {
        node.remove();
      }
    });
  }

  function ensureCanonicalMeta() {
    const canonicalUrl = currentCanonical();
    let canonical = document.querySelector('link[rel="canonical"]');
    if (!canonical) {
      canonical = document.createElement('link');
      canonical.rel = 'canonical';
      document.head.appendChild(canonical);
    }
    canonical.href = canonicalUrl;

    setMetaProperty('og:url', canonicalUrl);
    setMetaProperty('og:image', logoUrl);
    setMetaProperty('og:site_name', 'Poison Well Records');
    setMetaProperty('og:type', document.body.classList.contains('product-page') ? 'product' : 'website');
  }

  function ensureLaunchRobots() {
    if (currentFile() === '805-punk-shows-events.html') return;

    const liveHosts = ['poisonwellrecords.com', 'www.poisonwellrecords.com'];
    const shouldNoIndex = !liveHosts.includes(window.location.hostname);
    let robots = document.querySelector('meta[name="robots"]');

    if (!robots) {
      robots = document.createElement('meta');
      robots.name = 'robots';
      document.head.appendChild(robots);
    }

    robots.content = shouldNoIndex ? 'noindex,nofollow' : 'index,follow';
  }

  function ensureDigitalReleaseLinks() {
    const cards = document.querySelectorAll('.digital-band-card');
    if (!cards.length) return;

    const platformLabels = {
      spotify: 'Spotify',
      apple: 'Apple Music',
      youtube: 'YouTube'
    };

    const platformSvg = {
      spotify: '<svg viewBox="0 0 168 168" width="20" height="20" aria-hidden="true"><path fill="currentColor" d="M84 0C37.8 0 0 37.8 0 84s37.8 84 84 84 84-37.8 84-84S130.2 0 84 0zm38.5 121.2c-1.5 2.5-4.7 3.2-7.1 1.7-19.4-11.9-43.9-14.6-72.7-8-2.8.6-5.6-1.1-6.2-3.9-.6-2.8 1.1-5.6 3.9-6.2 31.6-7.2 58.7-4.1 80.8 9.4 2.4 1.5 3.2 4.6 1.7 7zm10.3-22.9c-1.9 3-5.9 4-8.9 2.1-22.2-13.6-56-17.6-82.3-9.6-3.4 1-7-1-8-4.4s1-7 4.4-8c29.9-9.1 67-4.7 92.6 11.1 3 1.8 4 5.8 2.2 8.8zm.9-23.8c-26.7-15.9-70.7-17.3-96.2-9.6-4.1 1.2-8.4-1.1-9.6-5.2-1.2-4.1 1.1-8.4 5.2-9.6 29.2-8.8 77.8-7.1 108.8 11.2 3.7 2.2 4.9 7 2.7 10.7-2.2 3.6-7 4.9-10.7 2.7z"/></svg>',
      apple: '<svg viewBox="0 0 24 24" width="20" height="20" aria-hidden="true"><path fill="currentColor" d="M17.57 12.6c-.03-3.22 2.64-4.76 2.76-4.83-1.5-2.2-3.84-2.5-4.66-2.53-1.98-.2-3.88 1.16-4.89 1.16-1.02 0-2.6-1.13-4.27-1.1-2.2.03-4.23 1.28-5.36 3.24-2.28 3.95-.58 9.78 1.63 12.98 1.08 1.56 2.36 3.3 4.04 3.24 1.61-.06 2.22-1.04 4.17-1.04 1.95 0 2.49 1.04 4.2 1 1.74-.03 2.84-1.58 3.91-3.15 1.24-1.8 1.75-3.55 1.78-3.64-.04-.01-3.39-1.3-3.42-5.33zm-3.11-8.18c.89-1.08 1.49-2.58 1.33-4.08-1.28.05-2.84.86-3.76 1.94-.82.95-1.54 2.48-1.35 3.94 1.43.11 2.89-.73 3.78-1.8z"/></svg>',
      youtube: '<svg viewBox="0 0 24 24" width="20" height="20" aria-hidden="true"><path fill="currentColor" d="M23.5 6.19a3.02 3.02 0 0 0-2.12-2.14C19.5 3.5 12 3.5 12 3.5s-7.5 0-9.38.55A3.02 3.02 0 0 0 .5 6.19 31.5 31.5 0 0 0 0 12a31.5 31.5 0 0 0 .5 5.81 3.02 3.02 0 0 0 2.12 2.14c1.88.55 9.38.55 9.38.55s7.5 0 9.38-.55a3.02 3.02 0 0 0 2.12-2.14A31.5 31.5 0 0 0 24 12a31.5 31.5 0 0 0-.5-5.81zM9.55 15.5V8.5l6.27 3.5-6.27 3.5z"/></svg>'
    };

    function searchUrl(platform, query) {
      const encoded = encodeURIComponent(query);
      if (platform === 'spotify') return 'https://open.spotify.com/search/' + encoded;
      if (platform === 'apple') return 'https://music.apple.com/us/search?term=' + encoded;
      return 'https://www.youtube.com/results?search_query=' + encoded;
    }

    function createSearchIcon(platform, query) {
      const link = document.createElement('a');
      link.href = searchUrl(platform, query);
      link.target = '_blank';
      link.rel = 'noopener';
      link.className = 'stream-icon ' + platform;
      link.title = platformLabels[platform];
      link.setAttribute('aria-label', platformLabels[platform]);
      link.innerHTML = platformSvg[platform];
      return link;
    }

    cards.forEach(function (card) {
      const titleNode = card.querySelector('.album-title');
      const bandNode = card.querySelector('.band-name');
      const streamLinks = card.querySelector('.stream-links');
      if (!titleNode || !bandNode || !streamLinks) return;

      const title = (titleNode.textContent || '')
        .replace(/\s+\((?:Vinyl|Combined Vinyl)\)\s*/gi, '')
        .trim();
      const band = (bandNode.textContent || '').trim();
      const query = [band, title].filter(Boolean).join(' ');
      if (!query) return;

      const buyVinyl = streamLinks.querySelector('.stream-icon.buy-vinyl');
      ['spotify', 'apple', 'youtube'].forEach(function (platform) {
        if (streamLinks.querySelector('.stream-icon.' + platform)) return;
        const icon = createSearchIcon(platform, query);
        if (buyVinyl) {
          streamLinks.insertBefore(icon, buyVinyl);
        } else {
          streamLinks.appendChild(icon);
        }
      });

      if (streamLinks.querySelector('.stream-icon.spotify, .stream-icon.apple, .stream-icon.youtube, .stream-icon.amazon, .stream-icon.bandcamp')) {
        const comingSoon = streamLinks.querySelector('.stream-coming-soon');
        if (comingSoon) comingSoon.remove();
      }
    });
  }

  sanitizeBrandArtifacts();
  ensureLaunchRobots();
  ensureCanonicalMeta();

  const images = document.querySelectorAll('img');
  images.forEach(function (img) {
    if (!img.getAttribute('alt')) img.setAttribute('alt', 'Poison Well Records - Ventura Punk Vinyl & Culture');
    if (!img.getAttribute('loading')) img.setAttribute('loading', 'lazy');
  });

  const yearNodes = document.querySelectorAll('[data-current-year]');
  const y = new Date().getFullYear();
  yearNodes.forEach(function (n) { n.textContent = String(y); });

  const jsonLdNodes = Array.from(document.querySelectorAll('script[type="application/ld+json"]'));
  const hasOrgSchema = jsonLdNodes.some(function (n) { return n.textContent.includes('"@type": "Organization"'); });
  const hasStoreSchema = jsonLdNodes.some(function (n) { return n.textContent.includes('"@type": "Store"'); });

  if (!hasOrgSchema) {
    const org = document.createElement('script');
    org.type = 'application/ld+json';
    org.textContent = JSON.stringify({
      '@context': 'https://schema.org',
      '@type': 'Organization',
      name: 'Poison Well Records',
      description: 'Ventura 805 punk vinyl label and online store archiving SoCal punk rock',
      url: baseUrl,
      logo: logoUrl,
      address: {
        '@type': 'PostalAddress',
        addressLocality: 'Ventura',
        addressRegion: 'CA',
        postalCode: '93001',
        addressCountry: 'US'
      },
      sameAs: [
        'https://www.tiktok.com/@poisonwellrecords',
        'https://www.instagram.com/poisonwellrecords',
        'https://www.discogs.com/user/PoisonWellRecords',
        bandcampUrl,
        'https://www.facebook.com/poisonwellrecords/',
        'https://www.youtube.com/@poisonwellrecords'
      ]
    });
    document.head.appendChild(org);
  }

  if (!hasStoreSchema) {
    const store = document.createElement('script');
    store.type = 'application/ld+json';
    store.textContent = JSON.stringify({
      '@context': 'https://schema.org',
      '@type': 'Store',
      'name': 'Poison Well Records Shop',
      'image': logoUrl,
      'description': '805 and SoCal punk vinyl record store and label shipping worldwide from Ventura, California',
      'address': {
        '@type': 'PostalAddress',
        'addressLocality': 'Ventura',
        'addressRegion': 'CA',
        'addressCountry': 'US'
      },
      'geo': {
        '@type': 'GeoCoordinates',
        'latitude': '34.2746',
        'longitude': '-119.2290'
      },
      'url': baseUrl + '/ventura-punk-record-store-online',
      'priceRange': '$$',
      'paymentAccepted': 'Credit Card, Debit Card',
      'currenciesAccepted': 'USD'
    });
    document.head.appendChild(store);
  }

  const hasBreadcrumbSchema = jsonLdNodes.some(function (n) { return n.textContent.includes('"@type":"BreadcrumbList"') || n.textContent.includes('"@type": "BreadcrumbList"'); });
  if (!hasBreadcrumbSchema) {
    const crumbLabel = {
      '/': 'Home',
      '/apparel': 'Apparel',
      '/ventura-punk-record-store-online': 'Vinyl',
      '/805-punk-bands': 'Artists & 805 Archive',
      '/about-poison-well-records': 'About',
      '/contact-wholesale': 'Contact / Wholesale',
      '/faq': 'FAQ',
      '/dr-know-live-cbgb-1989-ventura-hardcore': 'Dr. Know Live CBGB 1989'
    };
    const canon = currentCanonical();
    const suffix = canon.replace(baseUrl, '') || '/';
    const breadcrumb = {
      '@context': 'https://schema.org',
      '@type': 'BreadcrumbList',
      itemListElement: [{ '@type': 'ListItem', position: 1, name: 'Home', item: baseUrl + '/' }]
    };
    if (suffix !== '/') {
      breadcrumb.itemListElement.push({ '@type': 'ListItem', position: 2, name: crumbLabel[suffix] || document.title, item: canon });
    }
    const crumbNode = document.createElement('script');
    crumbNode.type = 'application/ld+json';
    crumbNode.textContent = JSON.stringify(breadcrumb);
    document.head.appendChild(crumbNode);
  }

  ensureGeoMeta();
  ensureFavicon();
  ensureFooterCredit();
  markCurrentNavLink();
  ensureAlertBar();
  ensureVinylBackground();
  initNavToggle();
  initBackToTop();
  ensureDigitalReleaseLinks();
  initMailtoForms();

  const stripeLinks = window.POISON_WELL_STRIPE_LINKS || {};
  const cjLinks = window.POISON_WELL_CJ_LINKS || {};
  const contactEmail = 'poisonwellrecords@gmail.com';
  const rarityProductKeys = new Set(['fluidFilledIDecline', 'splatterIDecline']);

  function clampCheckoutQuantity(value, max) {
    const parsed = parseInt(value, 10);
    if (!Number.isFinite(parsed)) return 1;
    return Math.max(1, Math.min(max || 10, parsed));
  }

  function setCheckoutBusy(triggerEl, isBusy, busyLabel) {
    if (!triggerEl) return;
    if (!triggerEl.dataset.originalLabel) {
      triggerEl.dataset.originalLabel = triggerEl.textContent.trim();
    }
    triggerEl.disabled = !!isBusy;
    triggerEl.setAttribute('aria-busy', isBusy ? 'true' : 'false');
    triggerEl.textContent = isBusy ? (busyLabel || 'Loading...') : triggerEl.dataset.originalLabel;
  }

  function fallbackToStripePaymentLink(productKey, quantity) {
    const checkoutUrl = stripeLinks[productKey];
    if (!checkoutUrl) return false;
    if (/\/test_/.test(checkoutUrl) && !/^(localhost|127\.0\.0\.1)$/i.test(window.location.hostname)) {
      return false;
    }
    const url = quantity > 1 ? (checkoutUrl + '?qty=' + quantity) : checkoutUrl;
    window.location.href = url;
    return true;
  }

  function isOnSiteStripeProduct(productKey) {
    return rarityProductKeys.has(productKey);
  }

  function getProductScope(triggerEl) {
    if (triggerEl && typeof triggerEl.closest === 'function') {
      return triggerEl.closest('article, .card, .urgent-cta, .container');
    }
    return null;
  }

  function getProductTitle(triggerEl) {
    const scope = getProductScope(triggerEl) || document;
    const titleNode = scope.querySelector('h1, h2, h3, .album-title');
    return titleNode ? titleNode.textContent.trim() : 'Poison Well Records release';
  }

  function getPreferredOffsiteLink(triggerEl) {
    const scope = getProductScope(triggerEl);
    if (!scope) return '';

    const links = Array.from(scope.querySelectorAll('a[href]')).filter(function (link) {
      const href = link.getAttribute('href') || '';
      if (!href || href === '#' || href.indexOf('mailto:') === 0) return false;
      if (href.charAt(0) === '/' || href.charAt(0) === '#') return false;
      return /^https?:\/\//i.test(href);
    });

    if (!links.length) return '';

    const priorities = ['bandcamp', 'amazon', 'apple', 'spotify', 'discogs', 'youtube'];
    for (let i = 0; i < priorities.length; i += 1) {
      const match = links.find(function (link) {
        const href = (link.getAttribute('href') || '').toLowerCase();
        const title = (link.getAttribute('title') || '').toLowerCase();
        const className = (link.className || '').toLowerCase();
        return href.indexOf(priorities[i]) !== -1 || title.indexOf(priorities[i]) !== -1 || className.indexOf(priorities[i]) !== -1;
      });
      if (match) return match.href;
    }

    return links[0].href;
  }

  function buildArchiveInquiryUrl(triggerEl) {
    const title = getProductTitle(triggerEl);
    const subject = 'Archive inquiry: ' + title;
    const body = [
      'Hi Poison Well Records,',
      '',
      'I am interested in this release:',
      title,
      '',
      'Please send details when you can.'
    ].join('\n');

    return 'mailto:' + contactEmail + '?subject=' + encodeURIComponent(subject) + '&body=' + encodeURIComponent(body);
  }

  function redirectToProductChannel(triggerEl) {
    const offsiteUrl = getPreferredOffsiteLink(triggerEl);
    if (offsiteUrl) {
      window.open(offsiteUrl, '_blank', 'noopener');
      return true;
    }

    window.location.href = buildArchiveInquiryUrl(triggerEl);
    return true;
  }

  async function createStripeCheckoutSession(productKey, options) {
    const response = await fetch('/api/create-checkout-session', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        productKey: productKey,
        quantity: options.quantity || 1,
        cancelPath: options.cancelPath || (window.location.pathname + window.location.search + window.location.hash)
      })
    });

    const payload = await response.json().catch(function () { return {}; });
    if (!response.ok || !payload.url) {
      throw new Error(payload.error || 'Unable to start Stripe checkout.');
    }
    return payload;
  }

  window.goToCheckout = async function (productKey, triggerEl) {
    if (!isOnSiteStripeProduct(productKey)) {
      redirectToProductChannel(triggerEl);
      return;
    }

    setCheckoutBusy(triggerEl, true, 'Opening Stripe...');
    try {
      const payload = await createStripeCheckoutSession(productKey, {
        quantity: 1
      });
      window.location.href = payload.url;
    } catch (error) {
      setCheckoutBusy(triggerEl, false);
      if (fallbackToStripePaymentLink(productKey, 1)) {
        return;
      }
      alert(error && error.message ? error.message : 'Stripe checkout is unavailable right now.');
    }
  };

  // Variant-aware checkout helper: accepts a base product key and the card element
  window.goToCheckoutVariant = async function (baseKey, cardEl, triggerEl) {
    if (!cardEl) cardEl = document.querySelector('.card');
    const size = (cardEl.dataset.size) || (cardEl.querySelector('select') ? cardEl.querySelector('select').value : '');
    const qty = clampCheckoutQuantity((cardEl.querySelector('.qty-input') && cardEl.querySelector('.qty-input').value) || 1, 10);
    const variantKey = size ? (baseKey + '_' + size) : baseKey;
    setCheckoutBusy(triggerEl, true, 'Opening Stripe...');
    try {
      const payload = await createStripeCheckoutSession(variantKey, {
        quantity: qty
      });
      window.location.href = payload.url;
      return;
    } catch (error) {
      setCheckoutBusy(triggerEl, false);
      if (fallbackToStripePaymentLink(variantKey, qty) || fallbackToStripePaymentLink(baseKey, qty)) {
        return;
      }
      alert(error && error.message ? error.message : ('No checkout path configured for ' + variantKey + '.'));
    }
  };

  window.goToCJProductVariant = function (baseKey, cardEl) {
    if (!cardEl) cardEl = document.querySelector('.card');
    const size = (cardEl.dataset.size) || (cardEl.querySelector('select') ? cardEl.querySelector('select').value : '');
    const variantKey = size ? (baseKey + '_' + size) : baseKey;
    const checkoutUrl = cjLinks[variantKey] || cjLinks[baseKey];
    if (!checkoutUrl) {
      alert('CJ product link is not set yet for ' + variantKey + '. Add it in cj-config.js');
      return;
    }
    window.location.href = checkoutUrl;
  };

  // Update buy button labels to reflect selected size and quantity
  window.updateBuyButton = function (cardEl) {
    if (!cardEl) return;
    const size = cardEl.dataset.size || (cardEl.querySelector('select') ? cardEl.querySelector('select').value : '');
    const qty = cardEl.querySelector('.qty-input') ? clampCheckoutQuantity(cardEl.querySelector('.qty-input').value || 1, 10) : 1;
    const priceNode = cardEl.querySelector('.price');
    const basePriceText = priceNode ? priceNode.textContent.trim() : '';
    const btn = cardEl.querySelector('.buy-btn');
    if (!btn) return;
    const provider = (cardEl.dataset.provider || '').toLowerCase();
    const labelPrefix = provider === 'cj'
      ? 'Order on CJ '
      : provider === 'autods'
        ? 'Order on AutoDS '
        : 'Buy ';
    const sizePart = size ? (size + ' ') : '';
    btn.textContent = labelPrefix + sizePart + '×' + qty + (basePriceText ? ' — ' + basePriceText : '');
    btn.dataset.originalLabel = btn.textContent;
  };

  function configureSalesChannels() {
    const checkoutButtons = Array.from(document.querySelectorAll('[onclick*="goToCheckout"]'));

    checkoutButtons.forEach(function (button) {
      const onclickValue = button.getAttribute('onclick') || '';
      const match = onclickValue.match(/goToCheckout\('([^']+)'/);
      if (!match) return;

      const productKey = match[1];
      if (isOnSiteStripeProduct(productKey)) return;

      const offsiteUrl = getPreferredOffsiteLink(button);
      button.removeAttribute('onclick');
      button.type = 'button';
      button.textContent = offsiteUrl ? 'Open Release Platform' : 'Contact About This Release';
      button.dataset.originalLabel = button.textContent;
      button.addEventListener('click', function (event) {
        event.preventDefault();
        redirectToProductChannel(button);
      });
    });
  }

  // Initialize buy button labels on pages with apparel cards
  function initApparelUI() {
    const apparelCards = Array.from(document.querySelectorAll('main .card')).filter(function (card) {
      return !!(card.querySelector('select') || card.querySelector('.qty-input'));
    });
    apparelCards.forEach(function (card) {
      // set initial dataset.size from select if present
      const sel = card.querySelector('select');
      if (sel && !card.dataset.size) card.dataset.size = sel.value;
      // ensure qty input has sensible bounds
      const q = card.querySelector('.qty-input');
      if (q) {
        q.setAttribute('min', '1');
        q.setAttribute('max', '10');
        q.addEventListener('input', function () {
          if (parseInt(q.value || 0, 10) < 1) q.value = 1;
          if (parseInt(q.value || 0, 10) > 10) q.value = 10;
        });
      }
      // attach change listeners to selects
      if (sel) sel.addEventListener('change', function () { card.dataset.size = sel.value; window.updateBuyButton(card); });
      // update button label now
      window.updateBuyButton(card);
    });
  }
  // Run on DOM ready
  function initLatestRelease() {
    const target = document.getElementById('latest-release-cards');
    if (!target) return;
    // prefer the first release card inside the releases grid
    const first = document.querySelector('.release-grid .release-card') || document.querySelector('.release-card');
    if (!first) return;
    const clone = first.cloneNode(true);
    // Tweak clone: remove duplicate buy links and adjust copy for 'Latest Release'
    const links = clone.querySelectorAll('.release-links a');
    if (links && links.length > 1) {
      // keep only the first (View Release) and the first Buy-like link if present
      let kept = [];
      // keep first link (assumed "View Release")
      kept.push(links[0]);
      // find a buy link by text that contains 'Buy' or 'Buy Vinyl' or 'Buy Now'
      for (let i = 1; i < links.length; i++) {
        const t = (links[i].textContent || '').toLowerCase();
        if (t.indexOf('buy') !== -1) { kept.push(links[i]); break; }
      }
      // remove all link nodes and re-append the kept ones
      const parent = links[0].parentNode;
      parent.innerHTML = '';
      kept.forEach(function (lnk) { parent.appendChild(lnk); });
    }
    // Adjust release-hook copy to highlight newest drop
    const hook = clone.querySelector('.release-hook');
    if (hook) {
      if (!hook.textContent.toLowerCase().includes('new')) {
        hook.textContent = 'Newest drop — ' + hook.textContent.trim();
      }
    }
    // Remove any duplicate buy buttons elsewhere inside the clone
    const buyButtons = clone.querySelectorAll('.buy-btn');
    if (buyButtons && buyButtons.length > 1) {
      for (let i = 1; i < buyButtons.length; i++) buyButtons[i].remove();
    }
    // Add a CTA link to the cloned card that opens an email prefilled with the release title
    const titleNode = clone.querySelector('h3');
    const releaseTitle = titleNode ? titleNode.textContent.trim() : 'Poison Well Records release';
    const cta = document.createElement('a');
    cta.className = 'btn primary';
    cta.href = 'mailto:poisonwellrecords@gmail.com?subject=' + encodeURIComponent('Interested in buying: ' + releaseTitle);
    cta.textContent = 'Contact to Buy';
    // append CTA into release-links if present, otherwise to clone
    const relLinks = clone.querySelector('.release-links');
    if (relLinks) {
      const wrapper = document.createElement('div');
      wrapper.style.marginTop = '0.6rem';
      wrapper.appendChild(cta);
      relLinks.parentNode.insertBefore(wrapper, relLinks.nextSibling);
    } else {
      clone.appendChild(cta);
    }
    target.appendChild(clone);
  }

  // Add 'Contact to Buy' CTA to all existing release cards on the page
  function initReleaseCTAs() {
    const cards = document.querySelectorAll('.release-card');
    if (!cards || cards.length === 0) return;
    cards.forEach(function (card) {
      if (card.__ctaAdded) return;
      const titleNode = card.querySelector('h3');
      const releaseTitle = titleNode ? titleNode.textContent.trim() : 'Poison Well Records release';
      const existing = card.querySelector('a[href^="mailto:"]');
      if (existing) { card.__ctaAdded = true; return; }
      const cta = document.createElement('a');
      cta.className = 'btn';
      cta.href = 'mailto:poisonwellrecords@gmail.com?subject=' + encodeURIComponent('Interested in buying: ' + releaseTitle);
      cta.textContent = 'Contact to Buy';
      // place CTA after release-links if present, otherwise append at end
      const relLinks = card.querySelector('.release-links');
      if (relLinks) {
        const wrapper = document.createElement('div');
        wrapper.style.marginTop = '0.6rem';
        wrapper.appendChild(cta);
        relLinks.parentNode.insertBefore(wrapper, relLinks.nextSibling);
      } else {
        card.appendChild(cta);
      }
      card.__ctaAdded = true;
    });
  }

  // Store Search & Filtering
  function initStoreSearch() {
    const searchInput = document.getElementById('store-search');
    if (!searchInput) return;

    searchInput.addEventListener('input', function(e) {
      const q = e.target.value.toLowerCase().trim();
      const productCards = document.querySelectorAll('.product-card, .vinyl-card, .card');
      
      productCards.forEach(card => {
        // Skip splash gate or unrelated cards if necessary, but keep it broad
        if (card.closest('#splash-gate') || card.closest('.footer')) return;
        
        const text = card.textContent.toLowerCase();
        const tags = (card.dataset.tags || '').toLowerCase();
        
        if (text.includes(q) || tags.includes(q)) {
          card.style.display = '';
        } else {
          card.style.display = 'none';
        }
      });
    });
  }

  function initVinylPreviewPlayer() { return; // disabled
    const shell = document.getElementById('vinyl-turntable-shell');
    const dropZone = document.getElementById('vinyl-drop-zone');
    const playButton = document.getElementById('vinyl-play-toggle');
    const audio = document.getElementById('vinyl-preview-audio');
    const recordLabel = document.getElementById('vinyl-record-label');
    const recordArtist = document.getElementById('vinyl-record-artist');
    const recordRelease = document.getElementById('vinyl-record-release');
    const recordTrack = document.getElementById('vinyl-record-track');
    const releaseTitle = document.getElementById('vinyl-release-title');
    const trackTitle = document.getElementById('vinyl-track-title');
    const artistName = document.getElementById('vinyl-artist-name');
    const catalogNumber = document.getElementById('vinyl-catalog-number');
    const speed = document.getElementById('vinyl-speed');
    const note = document.getElementById('vinyl-note');
    const statusText = document.getElementById('vinyl-status-text');
    const progressFill = document.getElementById('vinyl-progress-fill');
    const currentTimeNode = document.getElementById('vinyl-current-time');
    const totalTimeNode = document.getElementById('vinyl-total-time');
    const messageNode = document.getElementById('vinyl-turntable-message');
    const errorNode = document.getElementById('vinyl-error-message');
    const recordNode = document.getElementById('vinyl-record');
    const tonearmNode = document.getElementById('vinyl-tonearm');
    const meterBars = Array.from(document.querySelectorAll('.turntable-meter .meter-bar'));
    const crateItems = Array.from(document.querySelectorAll('.vinyl-crate-item'));

    if (!shell || !dropZone || !playButton || !audio || crateItems.length === 0) return;

    let selectedButton = crateItems.find(function (button) {
      return button.classList.contains('is-active');
    }) || crateItems[0];
    let queuedAutoplayId = '';

    function formatSeconds(value) {
      const safeValue = Math.max(0, Math.floor(value));
      const minutes = Math.floor(safeValue / 60);
      const seconds = safeValue % 60;
      return String(minutes).padStart(2, '0') + ':' + String(seconds).padStart(2, '0');
    }

    function readRecord(button) {
      const duration = parseFloat(button.dataset.previewDuration || '30');
      const start = parseFloat(button.dataset.previewStart || '0');
      return {
        id: button.dataset.recordId,
        artist: button.dataset.artist || 'Poison Well Records',
        releaseTitle: button.dataset.releaseTitle || 'Preview',
        trackTitle: button.dataset.trackTitle || 'Clip',
        catalogNumber: button.dataset.catalogNumber || '',
        speed: button.dataset.speed || '',
        note: button.dataset.note || '',
        accent: button.dataset.accent || '#c92b17',
        previewSrc: button.dataset.previewSrc || '',
        previewDuration: Number.isFinite(duration) ? duration : 30,
        previewStart: Number.isFinite(start) ? start : 0
      };
    }

    function previewWindow(record) {
      const duration = Number.isFinite(audio.duration) ? audio.duration : record.previewStart + record.previewDuration;
      const previewEnd = Math.min(record.previewStart + record.previewDuration, duration);
      return {
        start: record.previewStart,
        end: previewEnd,
        length: Math.max(0, previewEnd - record.previewStart)
      };
    }

    function setStatus(text) {
      if (statusText) statusText.textContent = text;
    }

    function setMessage(text) {
      if (messageNode) messageNode.textContent = text;
    }

    function setError(text) {
      if (!errorNode) return;
      if (text) {
        errorNode.hidden = false;
        errorNode.textContent = text;
      } else {
        errorNode.hidden = true;
        errorNode.textContent = '';
      }
    }

    function setMeterState(isPlaying) {
      meterBars.forEach(function (bar, index) {
        bar.classList.remove('is-active', 'is-tall-active');
        if (!isPlaying) return;
        if (index % 2 === 0) {
          bar.classList.add('is-active');
        } else {
          bar.classList.add('is-tall-active');
        }
      });
    }

    function setProgress(elapsed, total) {
      const progress = total > 0 ? Math.min((elapsed / total) * 100, 100) : 0;
      if (progressFill) progressFill.style.width = progress + '%';
      if (currentTimeNode) currentTimeNode.textContent = formatSeconds(elapsed);
      if (totalTimeNode) totalTimeNode.textContent = formatSeconds(total || 30);
    }

    function syncUiFromRecord(record) {
      recordArtist.textContent = record.artist;
      recordRelease.textContent = record.releaseTitle;
      recordTrack.textContent = record.trackTitle;
      releaseTitle.textContent = record.releaseTitle;
      trackTitle.textContent = record.trackTitle;
      artistName.textContent = record.artist;
      catalogNumber.textContent = record.catalogNumber;
      speed.textContent = record.speed;
      note.textContent = record.note;
      if (recordLabel) recordLabel.style.setProperty('--player-accent', record.accent);
      shell.style.setProperty('--player-accent', record.accent);
      setProgress(0, record.previewDuration);
      setStatus('Loading Preview');
      setMessage('Drag a record here or hit play to preview the loaded release.');
      setError('');
    }

    function pausePreview() {
      audio.pause();
      playButton.textContent = 'Play 30s Preview';
      recordNode.classList.remove('is-spinning');
      tonearmNode.classList.remove('is-engaged');
      setMeterState(false);
    }

    function playPreview(forceRestart) {
      const record = readRecord(selectedButton);
      const windowData = previewWindow(record);

      if (forceRestart || audio.currentTime < windowData.start || audio.currentTime >= windowData.end - 0.15) {
        audio.currentTime = windowData.start;
        setProgress(0, windowData.length || record.previewDuration);
      }

      setError('');
      const playPromise = audio.play();
      if (playPromise && typeof playPromise.then === 'function') {
        playPromise.then(function () {
          playButton.textContent = 'Pause Preview';
          recordNode.classList.add('is-spinning');
          tonearmNode.classList.add('is-engaged');
          setMeterState(true);
          setStatus('Preview Playing');
        }).catch(function () {
          pausePreview();
          setStatus('Preview Missing');
          setError('Preview file missing. Add the MP3 files listed in audio/previews/README.txt.');
        });
      } else {
        playButton.textContent = 'Pause Preview';
        recordNode.classList.add('is-spinning');
        tonearmNode.classList.add('is-engaged');
        setMeterState(true);
        setStatus('Preview Playing');
      }
    }

    function loadRecord(button, options) {
      const opts = options || {};
      crateItems.forEach(function (item) {
        item.classList.toggle('is-active', item === button);
      });
      selectedButton = button;
      queuedAutoplayId = opts.autoplay ? button.dataset.recordId || '' : '';
      const record = readRecord(button);
      syncUiFromRecord(record);
      pausePreview();
      audio.src = record.previewSrc;
      audio.load();
      shell.classList.remove('is-drop-target');
    }

    crateItems.forEach(function (button) {
      button.addEventListener('click', function () {
        loadRecord(button, { autoplay: false });
      });

      button.addEventListener('dragstart', function (event) {
        event.dataTransfer.effectAllowed = 'move';
        event.dataTransfer.setData('text/plain', button.dataset.recordId || '');
        button.classList.add('is-dragging');
        setMessage('Drop the record on the turntable to load and play the preview.');
      });

      button.addEventListener('dragend', function () {
        button.classList.remove('is-dragging');
        shell.classList.remove('is-drop-target');
        setMessage('Drag a record here or hit play to preview the loaded release.');
      });
    });

    dropZone.addEventListener('dragover', function (event) {
      event.preventDefault();
      shell.classList.add('is-drop-target');
      setMessage('Release the vinyl to drop the needle.');
    });

    dropZone.addEventListener('dragleave', function () {
      shell.classList.remove('is-drop-target');
      setMessage('Drag a record here or hit play to preview the loaded release.');
    });

    dropZone.addEventListener('drop', function (event) {
      event.preventDefault();
      const recordId = event.dataTransfer.getData('text/plain');
      const button = crateItems.find(function (item) {
        return item.dataset.recordId === recordId;
      });
      shell.classList.remove('is-drop-target');
      if (!button) return;
      loadRecord(button, { autoplay: true });
    });

    playButton.addEventListener('click', function () {
      if (!audio.paused) {
        pausePreview();
        setStatus('Preview Paused');
        return;
      }
      playPreview(false);
    });

    audio.addEventListener('loadedmetadata', function () {
      const record = readRecord(selectedButton);
      const windowData = previewWindow(record);
      audio.currentTime = windowData.start;
      setProgress(0, windowData.length || record.previewDuration);
      setStatus('Preview Ready');
      if (queuedAutoplayId && queuedAutoplayId === record.id) {
        queuedAutoplayId = '';
        playPreview(true);
      }
    });

    audio.addEventListener('timeupdate', function () {
      const record = readRecord(selectedButton);
      const windowData = previewWindow(record);
      const elapsed = Math.max(0, audio.currentTime - windowData.start);
      setProgress(Math.min(elapsed, windowData.length), windowData.length || record.previewDuration);
      if (audio.currentTime >= windowData.end) {
        audio.pause();
        audio.currentTime = windowData.start;
        setProgress(windowData.length, windowData.length || record.previewDuration);
        pausePreview();
        setStatus('Preview Complete');
      }
    });

    audio.addEventListener('error', function () {
      pausePreview();
      setStatus('Preview Missing');
      setProgress(0, readRecord(selectedButton).previewDuration);
      setError('Preview file missing. Add the MP3 files listed in audio/previews/README.txt.');
    });

    audio.addEventListener('pause', function () {
      if (audio.ended) return;
      if (audio.currentTime > 0 && audio.currentTime < audio.duration) {
        playButton.textContent = 'Resume Preview';
      }
    });

    audio.addEventListener('play', function () {
      playButton.textContent = 'Pause Preview';
      recordNode.classList.add('is-spinning');
      tonearmNode.classList.add('is-engaged');
      setMeterState(true);
      setStatus('Preview Playing');
    });

    loadRecord(selectedButton, { autoplay: false });
  }

  // Run on DOM ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function () { 
      initApparelUI(); 
      initLatestRelease(); 
      configureSalesChannels();
      initStoreSearch();
      initVinylPreviewPlayer();
    });
  } else {
    initApparelUI();
    initLatestRelease();
    configureSalesChannels();
    initStoreSearch();
    initVinylPreviewPlayer();
  }

  const gate = document.getElementById('splash-gate');
  const splashVideo = document.getElementById('splash-video');
  const splashVideoWrap = document.getElementById('splash-video-wrap');
  const splashVideoCta = document.getElementById('splash-video-cta');
  const splashEnterBtn = document.getElementById('splash-enter-btn');
  const enterHint = document.getElementById('enter-hint');
  if (gate && splashVideo) {
    window.__pwrSplashState = window.__pwrSplashState || { booted: false, released: false };
    window.__pwrSplashState.booted = true;
    document.body.classList.add('gate-active');
    let introFollowRaf = null;
    let hideGateTimer = null;
    let forcedOpenTimer = null;
    let gateReleased = false;
    const clamp = function (value, min, max) {
      return Math.max(min, Math.min(max, value));
    };
    const clearGateTimers = function () {
      if (hideGateTimer) {
        window.clearTimeout(hideGateTimer);
        hideGateTimer = null;
      }
      if (forcedOpenTimer) {
        window.clearTimeout(forcedOpenTimer);
        forcedOpenTimer = null;
      }
    };
    const resetIntroView = function () {
      splashVideo.style.setProperty('--intro-scale', '1');
      splashVideo.style.setProperty('--intro-shift-y', '0%');
      splashVideo.style.setProperty('--intro-origin-y', '50%');
    };
    const stopIntroFollow = function () {
      if (introFollowRaf) {
        window.cancelAnimationFrame(introFollowRaf);
        introFollowRaf = null;
      }
    };
    const runIntroFollow = function () {
      const duration = splashVideo.duration;
      const progress = duration && Number.isFinite(duration) ? clamp(splashVideo.currentTime / duration, 0, 1) : 0;
      const diveStart = 0.64;
      const diveProgress = clamp((progress - diveStart) / (1 - diveStart), 0, 1);
      const eased = Math.pow(diveProgress, 2.2);
      const maxScale = window.matchMedia('(max-width: 700px)').matches ? 1.72 : 1.52;
      const scale = 1 + ((maxScale - 1) * eased);
      const shiftY = (-1.4 * eased);
      const originY = 50 + (9 * eased);
      splashVideo.style.setProperty('--intro-scale', scale.toFixed(3));
      splashVideo.style.setProperty('--intro-shift-y', shiftY.toFixed(2) + '%');
      splashVideo.style.setProperty('--intro-origin-y', originY.toFixed(1) + '%');
      if (!splashVideo.paused && !splashVideo.ended && !gate.classList.contains('open')) {
        introFollowRaf = window.requestAnimationFrame(runIntroFollow);
      } else {
        introFollowRaf = null;
      }
    };
    const startIntroFollow = function () {
      stopIntroFollow();
      resetIntroView();
      introFollowRaf = window.requestAnimationFrame(runIntroFollow);
    };
    const scheduleGateFallback = function () {
      if (gateReleased || gate.classList.contains('video-awaiting-input')) {
        return;
      }
      if (forcedOpenTimer) {
        window.clearTimeout(forcedOpenTimer);
      }
      const durationMs = Number.isFinite(splashVideo.duration) && splashVideo.duration > 0
        ? Math.ceil(Math.max(2, splashVideo.duration - splashVideo.currentTime + 0.35) * 1000)
        : 12000;
      forcedOpenTimer = window.setTimeout(function () {
        openGate();
      }, durationMs);
    };
    const openGate = function () {
      if (gateReleased || gate.classList.contains('open')) return;
      gateReleased = true;
      if (window.__pwrSplashState) {
        window.__pwrSplashState.released = true;
      }
      clearGateTimers();
      stopIntroFollow();
      gate.classList.remove('video-awaiting-input');
      gate.classList.remove('video-playing');
      gate.classList.add('open');
      gate.style.pointerEvents = 'none';
      gate.setAttribute('aria-hidden', 'true');
      document.body.classList.remove('gate-active');
      hideGateTimer = window.setTimeout(function () {
        gate.classList.add('hide');
        gate.style.display = 'none';
      }, 620);
    };

    const showTapToPlay = function () {
      clearGateTimers();
      stopIntroFollow();
      resetIntroView();
      gate.classList.remove('video-playing');
      gate.classList.add('video-awaiting-input');
      if (enterHint) enterHint.textContent = 'Tap video to start intro, or use Enter Site Now';
      forcedOpenTimer = window.setTimeout(function () {
        if (gateReleased || !gate.classList.contains('video-awaiting-input')) {
          return;
        }
        if (enterHint) enterHint.textContent = 'Opening site...';
        openGate();
      }, 4000);
    };

    const markPlaying = function () {
      gate.classList.add('video-playing');
      gate.classList.remove('video-awaiting-input');
      if (enterHint) enterHint.textContent = 'Playing intro... (Tap to skip)';
      startIntroFollow();
      scheduleGateFallback();
      
      // Anti-freeze logic: If video time doesn't advance for 2 seconds while "playing", bypass
      let lastCheckTime = splashVideo.currentTime;
      let stallCounter = 0;
      const stallInterval = window.setInterval(function() {
        if (gateReleased) {
          window.clearInterval(stallInterval);
          return;
        }
        if (splashVideo.paused) return;
        
        if (Math.abs(splashVideo.currentTime - lastCheckTime) < 0.01) {
          stallCounter++;
          if (stallCounter >= 4) { // 2 seconds (0.5s * 4)
            console.log("Splash bypass via stall detection");
            window.clearInterval(stallInterval);
            openGate();
          }
        } else {
          stallCounter = 0;
          lastCheckTime = splashVideo.currentTime;
        }
      }, 500);
    };

    const playIntro = function () {
      if (gateReleased) {
        return;
      }
      splashVideo.muted = true;
      if (
        splashVideo.ended ||
        (Number.isFinite(splashVideo.duration) && splashVideo.duration > 0 && splashVideo.currentTime >= splashVideo.duration - 0.2)
      ) {
        splashVideo.currentTime = 0;
      }
      const playPromise = splashVideo.play();
      if (playPromise && typeof playPromise.then === 'function') {
        playPromise.then(function () {
          markPlaying();
        }).catch(function () {
          showTapToPlay();
        });
      } else {
        markPlaying();
      }

      // Safety timeout in case video hangs or fails to fire 'ended'
      window.setTimeout(function() {
        if (!gate.classList.contains('open')) {
          console.log("Splash bypass via safety timeout after 12s");
          openGate();
        }
      }, 12000); // 12s total for 10s video is safer than 10s exact
    };

    splashVideo.addEventListener('ended', openGate);
    splashVideo.addEventListener('error', openGate);
    splashVideo.addEventListener('loadedmetadata', scheduleGateFallback);
    splashVideo.addEventListener('canplay', scheduleGateFallback);
    ['stalled', 'suspend', 'abort', 'emptied'].forEach(function (eventName) {
      splashVideo.addEventListener(eventName, function () {
        if (gateReleased || gate.classList.contains('open')) {
          return;
        }
        if (splashVideo.currentTime > 0.1 && !splashVideo.paused) {
          scheduleGateFallback();
          return;
        }
        showTapToPlay();
      });
    });
    splashVideo.addEventListener('waiting', function () {
      if (gateReleased || gate.classList.contains('open')) {
        return;
      }
      if (splashVideo.currentTime < 0.1) {
        showTapToPlay();
      }
    });
    splashVideo.addEventListener('timeupdate', function () {
      if (
        !gateReleased &&
        Number.isFinite(splashVideo.duration) &&
        splashVideo.duration > 0 &&
        splashVideo.currentTime >= splashVideo.duration - 0.15
      ) {
        openGate();
      }
    });

    const startFromUser = function (e) {
      if (e && typeof e.preventDefault === 'function') e.preventDefault();
      if (gate.classList.contains('video-playing')) {
        openGate(); // Skip if already playing
      } else {
        playIntro();
      }
    };

    if (splashVideoWrap) {
      splashVideoWrap.addEventListener('click', function () {
        if (gate.classList.contains('video-awaiting-input')) {
          startFromUser();
        } else if (gate.classList.contains('video-playing')) {
          openGate(); // Click to skip
        }
      });
      splashVideoWrap.addEventListener('keydown', function (e) {
        if (e.key === 'Enter' || e.key === ' ') {
          if (gate.classList.contains('video-awaiting-input')) {
            startFromUser(e);
          } else if (gate.classList.contains('video-playing')) {
            openGate();
          }
        }
      });
    }

    if (splashVideoCta) {
      splashVideoCta.addEventListener('click', startFromUser);
    }

    if (splashEnterBtn) {
      splashEnterBtn.addEventListener('click', function (e) {
        if (e && typeof e.preventDefault === 'function') e.preventDefault();
        openGate();
      });
    }

    if (gate) {
      gate.addEventListener('click', function() {
        if (gate.classList.contains('video-awaiting-input')) {
          startFromUser();
        } else if (gate.classList.contains('video-playing')) {
          openGate();
        }
      });
    }

    resetIntroView();
    playIntro();
    window.setTimeout(function () {
      if (gateReleased) {
        return;
      }
      if (
        !gate.classList.contains('open') &&
        (
          !gate.classList.contains('video-playing') ||
          splashVideo.paused ||
          splashVideo.currentTime < 0.05 ||
          splashVideo.readyState < 2
        )
      ) {
        showTapToPlay();
      }
    }, 1500);
    window.setTimeout(function () {
      if (!gateReleased && !gate.classList.contains('video-awaiting-input')) {
        openGate();
      }
    }, 9000);
  }

  function initMailtoForms() {
    const forms = document.querySelectorAll('form[data-mailto-form]');
    if (!forms.length) return;

    forms.forEach(function (form) {
      form.addEventListener('submit', function (ev) {
        ev.preventDefault();

        const successNode = form.querySelector('.newsletter-success, .form-success');
        const submitBtn = form.querySelector('button[type="submit"]');
        const recipient = form.getAttribute('data-mailto-recipient') || 'poisonwellrecords@gmail.com';
        const subject = form.getAttribute('data-mailto-subject') || 'Poison Well Records Website Submission';
        const fd = new FormData(form);
        const lines = [];

        if (submitBtn) submitBtn.disabled = true;

        fd.forEach(function (value, key) {
          if (!value || key === 'bot-field' || key === 'form-name') return;
          const label = key
            .replace(/[-_]+/g, ' ')
            .replace(/\b\w/g, function (letter) { return letter.toUpperCase(); });
          lines.push(label + ': ' + String(value).trim());
        });

        const body = lines.length
          ? lines.join('\n')
          : 'New message from the Poison Well Records website.';

        if (successNode) {
          successNode.style.display = 'block';
          successNode.textContent = 'Your email app should open now. If it does not, email poisonwellrecords@gmail.com directly.';
        }

        window.location.href = 'mailto:' + recipient + '?subject=' + encodeURIComponent(subject) + '&body=' + encodeURIComponent(body);
        form.reset();

        window.setTimeout(function () {
          if (submitBtn) submitBtn.disabled = false;
        }, 250);
      });
    });
  }

  // Store Tabs Navigation
  const tabFootnotes = {
    'vinyl': 'Browse all vinyl releases from the Poison Well Records catalog.',
    'test-pressings': 'Ultra-limited pressings created for serious collectors. Once they disappear, they do not return.',
    'digital-releases': 'Stream and download the catalog. Past, present, and restored releases from the PWR archive.',
    'rarities': 'Hard-to-find recordings, historic releases, and underground artifacts preserved for the dedicated listener.'
  };

  const storeTabs = document.querySelectorAll('.store-tab');
  const tabContents = document.querySelectorAll('.tab-content');
  const tabFootnote = document.getElementById('tab-footnote');

  // Helper to activate a store tab by name (e.g. 'vinyl', 'test-pressings')
  function setActiveStoreTab(targetTab) {
    if (!targetTab) return;
    // Update active tab button
    storeTabs.forEach(function (t) { t.classList.remove('active'); if (t.getAttribute('data-tab') === targetTab) t.classList.add('active'); });
    // Update active content
    tabContents.forEach(function (content) {
      content.classList.remove('active');
      if (content.id === 'tab-' + targetTab) {
        content.classList.add('active');
      }
    });
    // Update footnote text
    if (tabFootnote && tabFootnotes[targetTab]) {
      tabFootnote.textContent = tabFootnotes[targetTab];
    }
  }

  if (storeTabs.length > 0) {
    storeTabs.forEach(function (tab) {
      tab.addEventListener('click', function () {
        const targetTab = this.getAttribute('data-tab');
        setActiveStoreTab(targetTab);
      });
    });

    // If the page loaded with a hash like #tab-vinyl, activate that tab
    if (window.location.hash && window.location.hash.indexOf('#tab-') === 0) {
      const ht = window.location.hash.replace('#tab-', '');
      setActiveStoreTab(ht);
    }

    // Wire header dropdown links to activate tabs client-side when on the store page
    const dropdownLinks = document.querySelectorAll('.nav-dropdown .dropdown-content a');
    if (dropdownLinks.length > 0) {
      dropdownLinks.forEach(function (link) {
        link.addEventListener('click', function (e) {
          // If already on the store page, prevent navigation and activate tab directly
          if (window.location.pathname === '/ventura-punk-record-store-online' || window.location.pathname === '/ventura-punk-record-store-online.html') {
            e.preventDefault();
            const hash = this.hash || this.getAttribute('href').split('#')[1] || '';
            const target = hash.replace('tab-', '');
            setActiveStoreTab(target);
            // close any open dropdowns by blurring and updating aria
            this.blur();
            const navDrop = this.closest('.nav-dropdown');
            if (navDrop) {
              const main = navDrop.querySelector('.nav-main');
              if (main) main.setAttribute('aria-expanded', 'false');
            }
          }
          // Otherwise, allow default navigation to the store page which will read the hash on load
        });
      });
    }
    // Enhance dropdown accessibility: toggle aria-expanded on hover/focus and close on Escape
    const navDropdowns = document.querySelectorAll('.nav-dropdown');
    navDropdowns.forEach(function (nd) {
      const main = nd.querySelector('.nav-main');
      const content = nd.querySelector('.dropdown-content');
      if (!main) return;
      main.setAttribute('aria-haspopup', 'true');
      main.setAttribute('aria-expanded', 'false');

      nd.addEventListener('mouseenter', function () { main.setAttribute('aria-expanded', 'true'); });
      nd.addEventListener('mouseleave', function () { main.setAttribute('aria-expanded', 'false'); });
      nd.addEventListener('focusin', function () { main.setAttribute('aria-expanded', 'true'); });
      nd.addEventListener('focusout', function (e) {
        // if focus moved outside the dropdown, close it
        if (!nd.contains(e.relatedTarget)) {
          main.setAttribute('aria-expanded', 'false');
        }
      });

      // Close dropdown on Escape key
      nd.addEventListener('keydown', function (e) {
        if (e.key === 'Escape' || e.key === 'Esc') {
          main.setAttribute('aria-expanded', 'false');
          main.focus();
        }
      });
    });
  }

  // Lightbox for product cover previews
  (function () {
    const body = document.body;
    const backdrop = document.createElement('div');
    backdrop.className = 'lightbox-backdrop';
    backdrop.setAttribute('role', 'dialog');
    backdrop.setAttribute('aria-hidden', 'true');

    const inner = document.createElement('div');
    inner.className = 'lightbox-inner';

    const img = document.createElement('img');
    img.alt = '';

    const caption = document.createElement('div');
    caption.className = 'lightbox-caption';

    const closeBtn = document.createElement('button');
    closeBtn.className = 'lightbox-close';
    closeBtn.innerHTML = '✕';
    closeBtn.type = 'button';

    // navigation buttons
    const navLeft = document.createElement('button');
    navLeft.className = 'lightbox-nav-button lightbox-prev';
    navLeft.innerHTML = '◀';
    const navRight = document.createElement('button');
    navRight.className = 'lightbox-nav-button lightbox-next';
    navRight.innerHTML = '▶';

    const navLeftWrap = document.createElement('div');
    navLeftWrap.className = 'lightbox-nav lightbox-nav-left';
    navLeftWrap.appendChild(navLeft);
    const navRightWrap = document.createElement('div');
    navRightWrap.className = 'lightbox-nav lightbox-nav-right';
    navRightWrap.appendChild(navRight);

    inner.appendChild(img);
    inner.appendChild(caption);
    backdrop.appendChild(inner);
    backdrop.appendChild(navLeftWrap);
    backdrop.appendChild(navRightWrap);
    backdrop.appendChild(closeBtn);
    body.appendChild(backdrop);

    let gallery = [];
    let currentIndex = -1;

    function openLightboxAt(index) {
      if (index < 0 || index >= gallery.length) return;
      const item = gallery[index];
      img.src = item.src;
      img.alt = item.alt || item.title || '';
      // show index and title
      caption.textContent = ((index + 1) + ' / ' + gallery.length) + (item.title ? ' — ' + item.title : '');
      currentIndex = index;
      backdrop.classList.add('open');
      backdrop.setAttribute('aria-hidden', 'false');
      closeBtn.focus();
    }

    function closeLightbox() {
      backdrop.classList.remove('open');
      backdrop.setAttribute('aria-hidden', 'true');
      img.src = '';
      currentIndex = -1;
    }

    function navigate(delta) {
      if (gallery.length === 0) return;
      let next = currentIndex + delta;
      if (next < 0) next = gallery.length - 1;
      if (next >= gallery.length) next = 0;
      openLightboxAt(next);
    }

    navLeft.addEventListener('click', function (e) { e.stopPropagation(); navigate(-1); });
    navRight.addEventListener('click', function (e) { e.stopPropagation(); navigate(1); });

    backdrop.addEventListener('click', function (e) {
      if (e.target === backdrop || e.target === closeBtn) closeLightbox();
    });
    document.addEventListener('keydown', function (e) {
      if (e.key === 'Escape') closeLightbox();
      if (e.key === 'ArrowLeft') navigate(-1);
      if (e.key === 'ArrowRight') navigate(1);
    });

    // Attach handlers to product images site-wide and build gallery
    function preloadImage(url) {
      if (!url) return;
      const p = new Image();
      p.src = url;
      return p;
    }

    function attachLightboxHandlers() {
      const imgs = Array.from(document.querySelectorAll('img.product-image'));
      gallery = imgs.map(function (el, i) {
        return {
          src: el.getAttribute('data-full-src') || el.getAttribute('src'),
          alt: el.getAttribute('alt') || '',
          title: (el.closest('.card') && el.closest('.card').querySelector('h3')) ? el.closest('.card').querySelector('h3').textContent.trim() : ''
        };
      });

      imgs.forEach(function (el, i) {
        if (el.__lightboxBound) return;
        el.__lightboxBound = true;
        // preload full-size on hover/focus
        const full = el.getAttribute('data-full-src') || el.getAttribute('src');
        el.addEventListener('mouseenter', function () { preloadImage(full); });
        el.addEventListener('focus', function () { preloadImage(full); });
        el.addEventListener('click', function (evt) {
          if (el.closest('a')) evt.preventDefault();
          openLightboxAt(i);
        });
      });
    }

    // Run once on load and expose attach function
    attachLightboxHandlers();
    window.PW_attachLightbox = attachLightboxHandlers;
  })();
})();
